changeSet.sql:
SET @ts_member_add_phone = (
    SELECT IF(
        EXISTS (
            SELECT 1
            FROM information_schema.COLUMNS
            WHERE TABLE_SCHEMA = DATABASE()
              AND TABLE_NAME = 'timesheet_project_member'
              AND COLUMN_NAME = 'member_phone'
        ),
        'SELECT 1',
        'ALTER TABLE `timesheet_project_member` ADD COLUMN `member_phone` VARCHAR(20) DEFAULT NULL COMMENT ''成员手机号'' AFTER `member_name`'
    )
);
PREPARE stmt FROM @ts_member_add_phone;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

SET @ts_member_drop_unique = (
    SELECT IF(
        EXISTS (
            SELECT 1
            FROM information_schema.STATISTICS
            WHERE TABLE_SCHEMA = DATABASE()
              AND TABLE_NAME = 'timesheet_project_member'
              AND INDEX_NAME = 'uk_ts_member_project_account'
        ),
        'ALTER TABLE `timesheet_project_member` DROP INDEX `uk_ts_member_project_account`',
        'SELECT 1'
    )
);
PREPARE stmt FROM @ts_member_drop_unique;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

ALTER TABLE `timesheet_project_member`
    MODIFY COLUMN `member_account` VARCHAR(100) DEFAULT NULL COMMENT '成员账号';

SET @ts_member_add_phone_index = (
    SELECT IF(
        EXISTS (
            SELECT 1
            FROM information_schema.STATISTICS
            WHERE TABLE_SCHEMA = DATABASE()
              AND TABLE_NAME = 'timesheet_project_member'
              AND INDEX_NAME = 'idx_ts_member_phone'
        ),
        'SELECT 1',
        'CREATE INDEX `idx_ts_member_phone` ON `timesheet_project_member` (`member_phone`)'
    )
);
PREPARE stmt FROM @ts_member_add_phone_index;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;
